from flask import Flask, request
from prometheus_client import Counter, start_http_server
import hashlib

app = Flask(__name__)

# Start the Prometheus metrics server
start_http_server(8000)

# Dictionary to hold counters for unique user-path combinations
user_path_counters = {}

def get_user_path_key(user_id, path):
    return f"{user_id}:{path}"

@app.route('/<path:path>', methods=['GET', 'POST'])
def track_requests(path):
    user_id = request.headers.get('X-User-ID', 'unknown')
    session_id = request.headers.get('X-Session-ID', 'unknown')

    # Create a unique key for the user-path combination
    user_path_key = get_user_path_key(user_id, path)

    # Initialize a new counter if it doesn't exist
    if user_path_key not in user_path_counters:
        user_path_counters[user_path_key] = Counter(
            f'http_requests_total{{user_id="{user_id}", session_id="{session_id}", path="{path}"}}',
            'Total number of HTTP requests for a user-path combination'
        )

    # Increment the counter
    user_path_counters[user_path_key].inc()

    return "Request tracked", 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)